import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { sendOTP, verifyOTP, register } from '../utils/api';

const WORK_TYPES = [
  'plumber', 'electrician', 'driver', 'helper', 'carpenter',
  'painter', 'cleaner', 'cook', 'security', 'gardener', 'other',
];

const STEPS = ['phone', 'otp', 'details'];

const Register = () => {
  const [step, setStep] = useState(0);
  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState('');
  const [form, setForm] = useState({ name: '', password: '', workType: '', profilePhoto: null });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSendOTP = async () => {
    if (!phone.match(/^\+?[0-9]{10,13}$/)) {
      setError('Enter a valid phone number');
      return;
    }
    setError('');
    setLoading(true);
    try {
      await sendOTP(phone);
      setSuccess('OTP sent! Check your SMS.');
      setStep(1);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to send OTP');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOTP = async () => {
    if (otp.length !== 6) { setError('Enter 6-digit OTP'); return; }
    setError('');
    setLoading(true);
    try {
      await verifyOTP(phone, otp);
      setSuccess('Phone verified! Fill your details.');
      setStep(2);
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid OTP');
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async () => {
    if (!form.name || !form.password || !form.workType) {
      setError('All fields are required');
      return;
    }
    setError('');
    setLoading(true);
    try {
      let lat = 12.9716, lng = 77.5946, area = 'Bangalore';
      if (navigator.geolocation) {
        await new Promise((res) =>
          navigator.geolocation.getCurrentPosition(
            (pos) => { lat = pos.coords.latitude; lng = pos.coords.longitude; res(); },
            () => res()
          )
        );
      }

      const fd = new FormData();
      fd.append('name', form.name);
      fd.append('phone', phone);
      fd.append('password', form.password);
      fd.append('workType', form.workType);
      fd.append('lat', lat);
      fd.append('lng', lng);
      fd.append('area', area);
      if (form.profilePhoto) fd.append('profilePhoto', form.profilePhoto);

      const res = await register(fd);
      login(res.data.user, res.data.token);
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-logo">Kaam<span>Pay</span></div>
      <p className="auth-tagline">Join Bangalore's local job network</p>

      <div className="auth-card">
        {/* Step indicators */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
          {STEPS.map((s, i) => (
            <div
              key={s}
              style={{
                flex: 1, height: 4, borderRadius: 2,
                background: i <= step ? 'var(--orange)' : 'var(--dark3)',
                transition: 'background 0.3s',
              }}
            />
          ))}
        </div>

        {error && <div className="alert alert-error">{error}</div>}
        {success && <div className="alert alert-success">{success}</div>}

        {/* Step 0: Phone */}
        {step === 0 && (
          <>
            <h2 style={{ color: '#fff', marginBottom: 6, fontFamily: 'var(--font-display)' }}>
              Your phone number 📱
            </h2>
            <p style={{ color: '#888', fontSize: '0.85rem', marginBottom: 20 }}>
              We'll send an OTP to verify
            </p>
            <div className="form-group">
              <label className="form-label">Phone (with country code)</label>
              <input
                className="form-input"
                type="tel"
                placeholder="+919876543210"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
              />
            </div>
            <button className="btn btn-primary btn-full" onClick={handleSendOTP} disabled={loading}>
              {loading ? 'Sending...' : 'Send OTP →'}
            </button>
          </>
        )}

        {/* Step 1: OTP */}
        {step === 1 && (
          <>
            <h2 style={{ color: '#fff', marginBottom: 6, fontFamily: 'var(--font-display)' }}>
              Enter OTP 🔐
            </h2>
            <p style={{ color: '#888', fontSize: '0.85rem', marginBottom: 20 }}>
              Sent to {phone}
            </p>
            <div className="form-group">
              <label className="form-label">6-digit OTP</label>
              <input
                className="form-input"
                type="number"
                placeholder="123456"
                maxLength={6}
                value={otp}
                onChange={(e) => setOtp(e.target.value.slice(0, 6))}
                style={{ fontSize: '1.4rem', letterSpacing: 8, textAlign: 'center' }}
              />
            </div>
            <button className="btn btn-primary btn-full" onClick={handleVerifyOTP} disabled={loading}>
              {loading ? 'Verifying...' : 'Verify OTP →'}
            </button>
            <button
              className="btn btn-outline btn-full"
              style={{ marginTop: 10 }}
              onClick={handleSendOTP}
              disabled={loading}
            >
              Resend OTP
            </button>
          </>
        )}

        {/* Step 2: Details */}
        {step === 2 && (
          <>
            <h2 style={{ color: '#fff', marginBottom: 6, fontFamily: 'var(--font-display)' }}>
              Your details 👷
            </h2>
            <div className="form-group">
              <label className="form-label">Full Name</label>
              <input
                className="form-input"
                placeholder="Raju Kumar"
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
              />
            </div>
            <div className="form-group">
              <label className="form-label">Password</label>
              <input
                className="form-input"
                type="password"
                placeholder="Min 6 characters"
                value={form.password}
                onChange={(e) => setForm({ ...form, password: e.target.value })}
              />
            </div>
            <div className="form-group">
              <label className="form-label">Work Type</label>
              <select
                className="form-select"
                value={form.workType}
                onChange={(e) => setForm({ ...form, workType: e.target.value })}
              >
                <option value="">Select your skill</option>
                {WORK_TYPES.map((w) => (
                  <option key={w} value={w}>{w.charAt(0).toUpperCase() + w.slice(1)}</option>
                ))}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Profile Photo (optional)</label>
              <input
                className="form-input"
                type="file"
                accept="image/*"
                onChange={(e) => setForm({ ...form, profilePhoto: e.target.files[0] })}
              />
            </div>
            <button className="btn btn-primary btn-full" onClick={handleRegister} disabled={loading}>
              {loading ? 'Creating account...' : 'Create Account 🎉'}
            </button>
          </>
        )}

        <p style={{ color: '#888', textAlign: 'center', marginTop: 16, fontSize: '0.9rem' }}>
          Already have an account?{' '}
          <Link to="/login" style={{ color: 'var(--orange)', fontWeight: 700 }}>Login</Link>
        </p>
      </div>
    </div>
  );
};

export default Register;
